import android.os.Vibrator;
import android.os.Build;
import android.os.VibrationEffect;
import android.os.VibrationAttributes;

Vibrator vb = (android.os.Vibrator) appContext.getSystemService(android.app.Service.VIBRATOR_SERVICE);
long[] vPattern = new long[] {0, 3000};

// The code below ensure the vibrate works on Android 13+ even if haptics are disabled
if (Build.VERSION.SDK_INT >= 33) {
  VibrationEffect effect = VibrationEffect.createWaveform(vPattern, -1);
  vb.vibrate(effect, VibrationAttributes.createForUsage(VibrationAttributes.USAGE_ACCESSIBILITY));
} else {
  vb.vibrate(vPattern, -1);
}
